static void print_hex(const uint8_t *p, size_t n) {
    for (size_t i = 0; i < n; i++) printf("%02x", p[i]);
    printf("\n");
}

int main(int argc, char **argv) {
    if (argc < 2) {
        fprintf(stderr, "usage: %s {hash|keyed|derive} [length=32] [seek=0]\n", argv[0]);
        return 1;
    }
    size_t length = 32;
    uint64_t seek = 0;
    if (argc >= 3) length = (size_t)atoll(argv[2]);
    if (argc >= 4) seek = (uint64_t)atoll(argv[3]);

    /* Read all of stdin */
    size_t cap = 65536, len = 0;
    uint8_t *buf = malloc(cap);
    int c;
    while ((c = fgetc(stdin)) != EOF) {
        if (len == cap) { cap *= 2; buf = realloc(buf, cap); }
        buf[len++] = (uint8_t)c;
    }

    blake3_hasher h;
    if (strcmp(argv[1], "hash") == 0) {
        blake3_hasher_init(&h);
        blake3_hasher_update(&h, buf, len);
    } else if (strcmp(argv[1], "keyed") == 0) {
        /* First 32 bytes are the key, rest is data */
        if (len < 32) { fprintf(stderr, "need 32+ bytes\n"); return 1; }
        uint8_t key[32];
        memcpy(key, buf, 32);
        blake3_hasher_init_keyed(&h, key);
        blake3_hasher_update(&h, buf + 32, len - 32);
