        blake3_hasher_init_derive_key(&h, ctx);
        blake3_hasher_update(&h, buf, len);
    } else {
        fprintf(stderr, "unknown mode\n");
        return 1;
    }

    uint8_t *out = malloc(length ? length : 1);
    blake3_hasher_finalize_seek(&h, seek, out, length);
    print_hex(out, length);
    return 0;
}

