/* Build usage string into buffer; `pos` describes the positional rendering */
static void build_usage(const char *progname, const char *pos, char *out, size_t cap) {
    /* Order: progname, [usage flag fragment], pos */
    /* We assemble fragment from seen flags, in the order they were seen.
       Only certain flags appear in the usage line (those that change usage). */
    char buf[256];
    buf[0] = '\0';
    size_t blen = 0;
    bool any = false;
    for (int i = 0; i < seen_count; i++) {
        const char *frag = NULL;
        switch (seen_order[i]) {
            case F_KEYED: frag = "--keyed"; break;
            case F_DERIVE_KEY: frag = "--derive-key <CONTEXT>"; break;
            case F_CHECK: frag = "--check"; break;
            case F_QUIET: frag = "--quiet"; break;
            case F_TAG: frag = "--tag"; break;
            case F_RAW: frag = "--raw"; break;
            case F_NO_NAMES: frag = "--no-names"; break;
            case F_NO_MMAP: frag = "--no-mmap"; break;
            case F_LENGTH: frag = "--length <LEN>"; break;
            case F_SEEK: frag = "--seek <SEEK>"; break;
            case F_NUM_THREADS: frag = "--num-threads <NUM>"; break;
            default: break;
        }
        if (frag) {
            size_t flen = strlen(frag);
            if (blen + flen + 2 < sizeof(buf)) {
                buf[blen++] = ' ';
                memcpy(buf + blen, frag, flen);
                blen += flen;
                buf[blen] = '\0';
                any = true;
            }
        }
    }
    if (!any) {
        snprintf(out, cap, "Usage: %s [OPTIONS] %s", progname, pos);
    } else {
        snprintf(out, cap, "Usage: %s%s %s", progname, buf, pos);
    }
}

