/* Initialize the appropriate hasher based on options. Returns true on success.
   On failure, may print an Error to stderr and exit. */
static void init_hasher_mode(blake3_hasher *h, const options_t *opts) {
    if (opts->keyed) {
        /* Read exactly 32 bytes from stdin. Error if fewer or more. */
        uint8_t key[33];
        size_t got = 0;
        while (got < 33) {
            ssize_t n = read(0, key + got, 33 - got);
            if (n < 0) {
                if (errno == EINTR) continue;
                fprintf(stderr, "Error: %s\n", strerror(errno));
                exit(1);
            }
            if (n == 0) break;
            got += (size_t)n;
        }
        if (got < 32) {
            fprintf(stderr, "Error: expected 32 key bytes from stdin, found %zu\n", got);
            exit(1);
        }
        if (got > 32) {
            fprintf(stderr, "Error: read more than 32 key bytes from stdin\n");
            exit(1);
        }
        blake3_hasher_init_keyed(h, key);
    } else if (opts->derive_key) {
        blake3_hasher_init_derive_key(h, opts->derive_ctx);
    } else {
        blake3_hasher_init(h);
    }
}

