static int run_hash_mode(const options_t *opts) {
    /* Make a list of inputs: if no files given, treat as stdin "-". */
    char *stdin_marker = "-";
    char **inputs;
    size_t n_inputs;
    if (opts->n_files == 0) {
        inputs = &stdin_marker;
        n_inputs = 1;
    } else {
        inputs = opts->files;
        n_inputs = opts->n_files;
    }

