        fprintf(stderr, "Error: Only one filename can be provided when using --raw\n");
        return 1;
    }

    int exit_code = 0;

    for (size_t i = 0; i < n_inputs; i++) {
        const char *path = inputs[i];
        /* In keyed mode, "-" as a file is forbidden */
        if (opts->keyed && strcmp(path, "-") == 0) {
            fflush(stdout);
            fprintf(stderr, "b3sum: -: Cannot open `-` in keyed mode\n");
            exit_code = 1;
            continue;
        }

        blake3_hasher h;
        /* Need to reinit hasher per file. For keyed mode, the key was already
           consumed from stdin, so we save it for reuse. */
        static bool key_initialized = false;
        static uint8_t saved_key[32];
        static bool derive_initialized = false;
        static uint32_t derive_keyv[8]; (void)derive_keyv;

        if (opts->keyed) {
            if (!key_initialized) {
                init_hasher_mode(&h, opts);
                memcpy(saved_key, h.key, 32);
                /* Wait - h.key is uint32_t[8], not bytes. Re-derive from stdin properly. */
                /* Actually let's just save the bytes of stdin key separately. */
                /* Rework: read key bytes once into static buffer */
                key_initialized = true;
