                blake3_hasher_init_keyed(&h, saved_key);
            }
        } else if (opts->derive_key) {
            blake3_hasher_init_derive_key(&h, opts->derive_ctx);
        } else {
            blake3_hasher_init(&h);
        }

        char *errmsg = NULL;
        int rc = hash_file_into(&h, path, opts->no_mmap, &errmsg);
        if (rc != 0) {
            /* Print "b3sum: <path>: <msg> (os error <errno>)" */
            int saved_errno = errno;
            char *escaped = escape_name(path);
            fprintf(stderr, "b3sum: %s: %s (os error %d)\n", escaped, errmsg ? errmsg : "error", saved_errno);
            free(escaped);
            free(errmsg);
            exit_code = 1;
            continue;
        }

        /* Output */
        size_t out_len = (size_t)opts->length;
        uint8_t *out = (uint8_t *)malloc(out_len ? out_len : 1);
        blake3_hasher_finalize_seek(&h, opts->seek, out, out_len);

        if (opts->raw) {
            print_hash_raw(out, out_len);
        } else if (opts->no_names) {
            print_hash_noname(out, out_len);
        } else if (opts->tag) {
            print_hash_tag(out, out_len, path);
        } else {
            print_hash_default(out, out_len, path);
        }
        free(out);
    }
    return exit_code;
}

