static int popcnt64(uint64_t x) {
    int c = 0;
    while (x) { c += (int)(x & 1); x >>= 1; }
    return c;
}

/* Push CV onto the stack. After pushing, merge pairs from the bottom up
   until the stack height matches the popcount of chunk_counter. */
static void push_cv(blake3_hasher *self, const uint8_t new_cv[32], uint64_t chunk_counter) {
    /* This is the standard BLAKE3 stack merging trick. */
    uint64_t total_chunks_after = chunk_counter + 1;
    /* Number of trailing zeros in (chunk_counter+1) is the # of merges. */
    /* Actually -- we should merge while cv_stack_len > popcount of total_after_excluding_new. */
    /* The standard algorithm: while popcnt(total - 1 - chunk_counter_of_first_in_subtree) ... */
    /* Simpler: keep merging while the number of CVs on stack equals what the merge condition says. */
    /* Standard approach: count trailing zeros of (chunk_counter + 1) = number of left-subtrees completed */

    /* Number of merges = trailing zeros of (chunk_counter + 1) */
    uint64_t tz_count = chunk_counter;  /* count trailing 0s of (tz_count + 1) is # of pairs to merge */
    int merges = 0;
    uint64_t v = chunk_counter + 1;
    while ((v & 1) == 0) { merges++; v >>= 1; }
    /* But careful: only merge while there are siblings on the stack. */
    /* Actually the BLAKE3 algorithm is: pushing a new CV means it's a right-child;
       merge with the left sibling on top of the stack to form parent, then check
       if that parent is also a right child of something, recurse. */

    /* Simpler stack-based algorithm: */
    uint8_t cv = new_cv[0]; (void)cv;
    /* Add new_cv, then while chunk_counter has trailing zeros after merging... */
    /* The trick is: merge stack while (chunk_counter & 1) == 1, then push, then shift counter right. */
    /* But chunk_counter could be 0 - we just push without merging. */

    uint8_t current[32];
    memcpy(current, new_cv, 32);

    /* Merge while chunk_counter is odd at the current level */
    uint64_t cc = chunk_counter;
    while ((cc & 1) == 1) {
        /* Pop left sibling */
        uint8_t left[32];
        memcpy(left, &self->cv_stack[(self->cv_stack_len - 1) * 32], 32);
        self->cv_stack_len--;
        uint8_t merged[32];
        parent_cv(left, current, self->key, self->flags, merged);
        memcpy(current, merged, 32);
        cc >>= 1;
    }
    /* Push current onto stack */
    memcpy(&self->cv_stack[self->cv_stack_len * 32], current, 32);
    self->cv_stack_len++;

    (void)tz_count; (void)merges;
}

